module quick_sort(
    input clk,
    input [15:0] data_in, // 4 x 4-bit inputs
    output reg [15:0] data_out // 4 x 4-bit sorted outputs
);
    reg [3:0] obf_arr [0:3];
    integer i, j;
    reg [3:0] temp;

    always @(posedge clk) begin
        // Load the input data into the array
        obf_arr[0] <= data_in[15:12];
        obf_arr[1] <= data_in[11:8];
        obf_arr[2] <= data_in[7:4];
        obf_arr[3] <= data_in[3:0];

        // Perform a simple bubble sort (as a replacement for quick sort for simplicity)
        for (i = 0; i < 4; i = i + 1) begin
            for (j = i + 1; j < 4; j = j + 1) begin
                if (obf_arr[i] > obf_arr[j]) begin
                    temp = obf_arr[i];
                    obf_arr[i] = obf_arr[j];
                    obf_arr[j] = temp;
                end
            end
        end

        // Load the sorted array back into the output
        data_out <= {obf_arr[3], obf_arr[2], obf_arr[1], obf_arr[0]};
    end
endmodule
